B2 = [-0.193616, -0.058071, -0.138813, -0.127977, 0.141645, 0.101046, -0.288225, -0.01777, -0.00765, -0.236619, 0.17776, -0.259524, -0.098884, -0.0652, 0.447363, 0.034592]
W3 = [
        [-0.127748, -0.082504, -0.029932, -0.210156, 0.193438, -0.016849, -0.124396, -0.179828, 0.059258, -0.049812, -0.131772, 0.116194, 0.171722, -0.146301, -0.044857, 0.131964],
        [0.022784, -0.154826, -0.020673, -0.194975, -0.054691, -0.04172, -0.128177, 0.066313, -0.086236, -0.087408, -0.129116, 0.085877, -0.14512, -0.134379, -0.0347, 0.203292],
        [-0.162906, -0.20544, -0.034423, -0.159002, 0.215947, -0.055674, -0.09996, -0.170744, -0.018139, -0.150953, 0.05745, 0.138778, 0.206971, 0.03596, 0.032116, 0.161925],
        [-0.127748, -0.0706, 0.067381, -0.202369, -0.028411, -0.10626, -0.093389, -0.249684, -0.055576, -0.080529, -0.204106, -0.121315, 0.126756, 0.047887, 0.070342, 0.116801]
    ]
B3 = [0.043535, -0.403527, -0.002285, -0.072282]

SAMPLE_RATE_MS = 50
NUM_SAMPLES    = 30
GESTURES       = ['Forehand', 'Backhand', 'Overhead', 'None']

# neural net forward pass
def relu(x):
    return [v if v > 0 else 0.0 for v in x]

def linear(x, w, b):
    return [
        sum(w[i][j] * x[j] for j in range(len(x))) + b[i]
        for i in range(len(b))
    ]

def predict(x):
    x = relu(linear(x, W1, B1))
    x = relu(linear(x, W2, B2))
    x = linear(x, W3, B3)
    return x.index(max(x))

def collect_sample():
    sample = []
    for _ in range(NUM_SAMPLES):
        ax, ay, az = motion_sensor.acceleration(False)
        gx, gy, gz = motion_sensor.angular_velocity(False)
        sample.extend([ax, ay, az, gx, gy, gz])
        time.sleep_ms(SAMPLE_RATE_MS)
    return sample

# Main Loop
print("Ready. Press LEFT button to classify.")
light_matrix.write("?")

last_position = None

while True:
    # Wait for left button press
    while not button.pressed(button.LEFT):
        time.sleep_ms(50)
    # Wait for release
    while button.pressed(button.LEFT):
        time.sleep_ms(50)

    # Countdown
    for i in range(3, 0, -1):
        light_matrix.write(str(i))
        time.sleep(1)

    # Flash to signal go
    light_matrix.show([9] * 25)
    time.sleep_ms(200)
    light_matrix.show([0] * 25)

    # Collect and classify
    sample  = collect_sample()
    gesture = predict(sample)

    # Show first initial
    light_matrix.write(GESTURES[gesture][0])
    print(GESTURES[gesture])
    time.sleep(2)
    light_matrix.write("?")
